interface SystemType {
  name: string;
  combinations: number[]; // Sizes of combinations (e.g. [2, 3] for a Trixie)
  totalBets: number;
}

const SYSTEMS: Record<string, SystemType> = {
  Trixie: { name: 'Trixie', combinations: [2, 3], totalBets: 4 },
  Patent: { name: 'Patent', combinations: [1, 2, 3], totalBets: 7 },
  Yankee: { name: 'Yankee', combinations: [2, 3, 4], totalBets: 11 },
  Lucky15: { name: 'Lucky 15', combinations: [1, 2, 3, 4], totalBets: 15 },
  Canadian: { name: 'Canadian (Super Yankee)', combinations: [2, 3, 4, 5], totalBets: 26 },
};

const SystemCalculator: React.FC = () => {
  const [selectedSystem, setSelectedSystem] = useState<string>('Yankee');
  const [unitStake, setUnitStake] = useState('1');
  const [selections, setSelections] = useState(['2.00', '2.00', '2.00', '2.00']);
  const [results, setResults] = useState({ totalStake: 0, totalReturn: 0, profit: 0 });

  useEffect(() => {
    const system = SYSTEMS[selectedSystem];
    if (!system) return;

    const uStake = parseFloat(unitStake) || 0;
    const odds = selections.map(s => parseFloat(s) || 1);
    let totalRet = 0;

    system.combinations.forEach(size => {
      const combos = getCombinations(odds, size);
      combos.forEach(combo => {
        totalRet += combo.reduce((acc, o) => acc * o, 1) * uStake;
      });
    });

    const totalStake = system.totalBets * uStake;
    setResults({
      totalStake: parseFloat(totalStake.toFixed(2)),
      totalReturn: parseFloat(totalRet.toFixed(2)),
      profit: parseFloat((totalRet - totalStake).toFixed(2))
    });
  }, [selectedSystem, unitStake, selections]);

  const handleSystemChange = (name: string) => {
    setSelectedSystem(name);
    const system = SYSTEMS[name];
    const maxSel = Math.max(...system.combinations);
    const newSels = Array(maxSel).fill('2.00');
    setSelections(newSels);
