            <div className="grid grid-cols-2 gap-3">
              {selections.map((s, idx) => (
                <div key={idx} className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-[10px] font-bold text-slate-400">#{idx+1}</span>
                  <input 
                    type="number" 
                    step="0.01" 
                    value={s} 
                    onChange={e => {
                      const newSels = [...selections];
                      newSels[idx] = e.target.value;
                      setSelections(newSels);
                    }}
                    className="w-full pl-8 pr-3 py-2 bg-white border border-slate-200 rounded-lg outline-none focus:border-blue-500"
                  />
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-gradient-to-br from-indigo-600 to-blue-700 text-white rounded-3xl p-8 shadow-xl">
            <h3 className="text-xs font-bold uppercase tracking-widest opacity-70 mb-6">Total Calculation</h3>
