    // but here we'll just reset or attempt a conversion to keep it simple.
  }, [oddsFormat]);

  useEffect(() => {
    calculate();
  }, [stake, legs, oddsFormat]);

  const calculate = () => {
    const s = parseFloat(stake) || 0;
    const combinedOdds = legs.reduce((acc, leg) => acc * toDecimal(leg.odds, oddsFormat), 1);
    const returns = s * combinedOdds;
    setResults({
      returns: parseFloat(returns.toFixed(2)),
      profit: parseFloat((returns - s).toFixed(2))
    });
  };

  const addLeg = () => {
    setLegs([...legs, { id: Date.now(), odds: fromDecimal(1.5, oddsFormat) }]);
  };

  const removeLeg = (id: number) => {
    if (legs.length > 1) {
      setLegs(legs.filter(l => l.id !== id));
    }
  };

  const handleUpdateLeg = (id: number, val: string) => {
    setLegs(legs.map(l => l.id === id ? { ...l, odds: val } : l));
  };

  const generateAIInsights = async () => {
    setLoadingInsights(true);
    const text = await getBettingInsights('Standard Bet / Accumulator', { stake, legs, results, oddsFormat });
    setInsights(text);
    setLoadingInsights(false);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      <div className="lg:col-span-2 space-y-6">
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-2">Total Stake</label>
          <div className="relative">
            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">$</span>
            <input 
              type="number" 
              value={stake} 
              onChange={(e) => setStake(e.target.value)}
              className="w-full pl-8 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              placeholder="0.00"
            />
          </div>
        </div>

        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <h3 className="font-semibold text-slate-800">Selections ({oddsFormat})</h3>
            <button 
              onClick={addLeg}
              className="text-sm font-medium text-blue-600 hover:text-blue-700 flex items-center gap-1"
            >
              <i className="fa-solid fa-plus text-xs"></i> Add Leg
            </button>
          </div>

          {legs.map((leg, index) => (
            <div key={leg.id} className="flex items-center gap-3 p-4 bg-slate-50 rounded-xl border border-slate-100">
              <span className="w-8 h-8 bg-white rounded-full flex items-center justify-center text-xs font-bold text-slate-400 border border-slate-200">
                {index + 1}
              </span>
              <div className="flex-1">
                <input 
                  type="text" 
                  value={leg.odds}
                  onChange={(e) => handleUpdateLeg(leg.id, e.target.value)}
                  className="w-full bg-white px-3 py-2 border border-slate-200 rounded-lg outline-none focus:border-blue-500 transition-all text-sm"
                  placeholder={`Odds (${oddsFormat})`}
                />
              </div>
              <button 
                onClick={() => removeLeg(leg.id)}
                className="text-slate-400 hover:text-red-500 transition-colors px-2"
              >
                <i className="fa-solid fa-trash-can"></i>
              </button>
            </div>
          ))}
        </div>
      </div>

      <div className="space-y-6">
        <div className="bg-blue-600 text-white rounded-2xl p-6 shadow-xl shadow-blue-200">
          <h3 className="text-sm font-semibold uppercase tracking-wider opacity-80 mb-4">Summary</h3>
          <div className="space-y-4">
            <div>
              <p className="text-xs opacity-70 mb-1">Total Returns</p>
              <p className="text-4xl font-bold">${results.returns}</p>
            </div>
            <div>
              <p className="text-xs opacity-70 mb-1">Total Profit</p>
              <p className="text-2xl font-bold text-green-300">+${results.profit}</p>
            </div>
          </div>
        </div>

        <div className="bg-slate-50 border border-slate-200 rounded-2xl p-6">
          <div className="flex items-center justify-between mb-4">
            <h4 className="font-bold text-slate-800 flex items-center gap-2">
              <i className="fa-solid fa-wand-magic-sparkles text-blue-500"></i>
              AI Insight
            </h4>
            <button 
              onClick={generateAIInsights}
              disabled={loadingInsights}
              className="text-xs bg-white border border-slate-200 px-3 py-1.5 rounded-lg hover:bg-slate-100 transition-all disabled:opacity-50"
            >
              {loadingInsights ? 'Analyzing...' : 'Refresh'}
            </button>
          </div>
          <div className="text-sm text-slate-600 leading-relaxed max-h-64 overflow-y-auto custom-scrollbar">
            {insights ? insights : "Click 'Refresh' to get an AI breakdown of your bet structure, risk profile, and bankroll advice."}
          </div>
        </div>
      </div>
    </div>
  );
};

export default BetCalculator;

import React, { useState, useEffect } from 'react';
import { useSettings } from '../../App';
import { toDecimal, fromDecimal } from '../../utils/calculations';

const ArbCalculator: React.FC = () => {
  const { oddsFormat } = useSettings();
  const [totalStake, setTotalStake] = useState<string>('100');
  const [outcomes, setOutcomes] = useState([
    { odds: fromDecimal(2.1, oddsFormat), stake: 0, profit: 0 }, 
    { odds: fromDecimal(2.1, oddsFormat), stake: 0, profit: 0 }
  ]);
  const [arbPercentage, setArbPercentage] = useState<number>(0);
  const [isArb, setIsArb] = useState(false);

  useEffect(() => {
    calculate();
  }, [totalStake, outcomes.map(o => o.odds), oddsFormat]);

  const calculate = () => {
    const totalS = parseFloat(totalStake) || 0;
    const invSum = outcomes.reduce((acc, o) => acc + (1 / toDecimal(o.odds, oddsFormat)), 0);
    const arbPct = invSum * 100;
    setArbPercentage(parseFloat(arbPct.toFixed(2)));
    setIsArb(arbPct < 100);

    const updatedOutcomes = outcomes.map(o => {
      const odds = toDecimal(o.odds, oddsFormat);
      const s = (totalS / (odds * invSum));
      const p = (s * odds) - totalS;
      return { ...o, stake: parseFloat(s.toFixed(2)), profit: parseFloat(p.toFixed(2)) };
    });
    setOutcomes(updatedOutcomes);
  };

  const addOutcome = () => {
    if (outcomes.length < 5) setOutcomes([...outcomes, { odds: fromDecimal(3.0, oddsFormat), stake: 0, profit: 0 }]);
  };

  const removeOutcome = (idx: number) => {
    if (outcomes.length > 2) setOutcomes(outcomes.filter((_, i) => i !== idx));
  };

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row gap-8 items-start">
        <div className="flex-1 space-y-6 w-full">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-2">Total Target Stake</label>
            <input 
              type="number" 
              value={totalStake} 
              onChange={(e) => setTotalStake(e.target.value)}
              className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            />
          </div>

          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <h3 className="font-semibold">Market Outcomes ({oddsFormat})</h3>
              <button onClick={addOutcome} className="text-sm text-blue-600 font-medium">+ Add Outcome</button>
            </div>
            {outcomes.map((o, idx) => (
              <div key={idx} className="flex gap-4 p-4 bg-white border border-slate-100 rounded-xl shadow-sm items-center">
                <div className="flex-1">
                  <label className="text-[10px] uppercase font-bold text-slate-400 block mb-1">Odds</label>
                  <input 
                    type="text" 
                    value={o.odds}
                    onChange={(e) => {
                      const newOutcomes = [...outcomes];
                      newOutcomes[idx].odds = e.target.value;
                      setOutcomes(newOutcomes);
                    }}
                    className="w-full bg-slate-50 px-3 py-2 border border-slate-200 rounded-lg"
                  />
                </div>
                <div className="flex-1">
                  <label className="text-[10px] uppercase font-bold text-slate-400 block mb-1">Suggested Stake</label>
                  <div className="px-3 py-2 bg-slate-100 border border-slate-200 rounded-lg text-slate-700 font-medium">
                    ${o.stake}
                  </div>
                </div>
                <button onClick={() => removeOutcome(idx)} className="mt-5 text-slate-300 hover:text-red-500 transition-colors">
                  <i className="fa-solid fa-xmark"></i>
                </button>
              </div>
            ))}
          </div>
        </div>

        <div className="w-full md:w-80 space-y-6">
          <div className={`p-6 rounded-2xl border-2 transition-all ${isArb ? 'border-green-500 bg-green-50' : 'border-slate-200 bg-slate-50'}`}>
            <div className="flex items-center justify-between mb-4">
              <span className="text-sm font-bold uppercase text-slate-500">Arb Status</span>
              {isArb ? (
                <span className="bg-green-500 text-white text-[10px] font-bold px-2 py-0.5 rounded">OPPORTUNITY</span>
              ) : (
                <span className="bg-slate-300 text-white text-[10px] font-bold px-2 py-0.5 rounded">NO ARB</span>
              )}
            </div>
            <div className="text-center">
              <p className="text-xs text-slate-500 mb-1">Implied Probability Sum</p>
              <p className={`text-4xl font-black ${isArb ? 'text-green-600' : 'text-slate-700'}`}>
                {arbPercentage}%
              </p>
              {isArb && (
                <p className="text-sm font-medium text-green-700 mt-2">
                  Guaranteed Profit: ${outcomes[0].profit} ({( (outcomes[0].profit / parseFloat(totalStake)) * 100).toFixed(2)}%)
                </p>
              )}
            </div>
          </div>

          <div className="p-5 bg-blue-50 rounded-xl border border-blue-100">
            <h4 className="text-xs font-bold text-blue-700 uppercase mb-2">What is Arbitrage?</h4>
            <p className="text-xs text-blue-900 leading-relaxed">
              Arbing involves placing bets on all possible outcomes of an event with different bookmakers to lock in a profit regardless of the result.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ArbCalculator;

import React, { useState, useEffect, useMemo } from 'react';
import { useSettings } from '../../App';
import { toDecimal, fromDecimal, getCombinations } from '../../utils/calculations';

type Outcome = 'WIN' | 'LOSS' | 'VOID';

interface BetEntry {
  id: string;
  odds: string;
  outcome: Outcome;
}

const SystemCalculator: React.FC = () => {
  const { oddsFormat } = useSettings();
  const [numSelections, setNumSelections] = useState<number>(4);
  const [systemK, setSystemK] = useState<number>(2);
  const [totalStake, setTotalStake] = useState<string>('100');
  const [bets, setBets] = useState<BetEntry[]>([]);

  // Initialize or adjust bets when numSelections changes
  useEffect(() => {
    setBets(prev => {
      const next = [...prev];
      if (next.length < numSelections) {
        for (let i = next.length; i < numSelections; i++) {
          next.push({ id: Math.random().toString(36).substr(2, 9), odds: fromDecimal(1.8, oddsFormat), outcome: 'WIN' });
        }
      } else {
        return next.slice(0, numSelections);
      }
      return next;
    });

    if (systemK > numSelections) {
      setSystemK(numSelections);
    }
  }, [numSelections]);

  const combinations = useMemo(() => {
    const indices = Array.from({ length: numSelections }, (_, i) => i);
    return getCombinations(indices, systemK);
  }, [numSelections, systemK]);

  const rowsCount = combinations.length;
  const stakePerRow = rowsCount > 0 ? parseFloat(totalStake) / rowsCount : 0;

  const calculateTotalReturn = (kSize: number) => {
    const indices = Array.from({ length: numSelections }, (_, i) => i);
    const combos = getCombinations(indices, kSize);
    const unitStake = parseFloat(totalStake) / combos.length;

    let totalRet = 0;
    combos.forEach(combo => {
      let comboOdds = 1;
      let isLost = false;
      for (const idx of combo) {
        const bet = bets[idx];
        if (!bet) continue;
        const decOdds = toDecimal(bet.odds, oddsFormat);
        if (bet.outcome === 'WIN') {
          comboOdds *= decOdds;
        } else if (bet.outcome === 'VOID') {
          comboOdds *= 1; // Void bet counts as 1.00 odds
        } else {
          isLost = true;
          break;
        }
      }
      if (!isLost) {
        totalRet += comboOdds * unitStake;
      }
    });
    return totalRet;
  };

  const currentReturn = calculateTotalReturn(systemK);
  const correctCount = bets.filter(b => b.outcome === 'WIN').length;

  // Data for the comparison chart
  const comparisonData = useMemo(() => {
    const sizes = [1, ...Array.from({ length: Math.max(0, numSelections - 2) }, (_, i) => i + 2), numSelections];
    const uniqueSizes = Array.from(new Set(sizes.filter(s => s <= numSelections))).sort((a, b) => a - b);

    return uniqueSizes.map(s => {
      let label = `${s}/${numSelections}`;
      if (s === 1) label = "Singles";
      if (s === numSelections) label = "Accumulator";
      return {
        label,
        value: calculateTotalReturn(s)
      };
    });
  }, [bets, numSelections, totalStake, oddsFormat]);

  const maxChartValue = Math.max(...comparisonData.map(d => d.value), parseFloat(totalStake) * 1.2, 10);

  return (
    <div className="space-y-10">
      {/* Input Section */}
      <section>
        <h2 className="text-xl font-bold text-slate-800 mb-6">Input</h2>
        <div className="bg-slate-50 border border-slate-200 rounded-2xl p-6 space-y-4">
          <div className="flex flex-col md:flex-row gap-4 items-center">
            <span className="font-bold text-slate-700 w-24">System</span>
            <div className="flex gap-2 flex-1 w-full">
              <select 
                value={systemK}
                onChange={(e) => setSystemK(parseInt(e.target.value))}
                className="flex-1 bg-white border border-slate-300 rounded-lg px-3 py-2 text-blue-600 font-bold focus:ring-2 focus:ring-blue-500 outline-none"
              >
                {Array.from({ length: numSelections }, (_, i) => i + 1).map(v => (
                  <option key={v} value={v}>{v}</option>
                ))}
              </select>
              <select 
                value={numSelections}
                onChange={(e) => setNumSelections(parseInt(e.target.value))}
                className="flex-1 bg-white border border-slate-300 rounded-lg px-3 py-2 text-blue-600 font-bold focus:ring-2 focus:ring-blue-500 outline-none"
              >
                {[2, 3, 4, 5, 6, 7, 8].map(v => (
                  <option key={v} value={v}>{v}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="flex flex-col md:flex-row gap-4 items-center">
            <span className="font-bold text-slate-700 w-24">Total Stake</span>
            <input 
              type="number"
              value={totalStake}
              onChange={(e) => setTotalStake(e.target.value)}
              className="flex-1 w-full bg-white border border-slate-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 outline-none"
            />
          </div>

          <div className="space-y-2 pt-4">
            <span className="font-bold text-slate-700 block mb-2">Bets</span>
            {bets.map((bet, idx) => (
              <div key={bet.id} className="flex flex-wrap md:flex-nowrap gap-3 items-center">
                <span className="text-slate-500 text-sm w-16">Bet {idx + 1}</span>
                <input 
                  type="text"
                  value={bet.odds}
                  onChange={(e) => {
                    const next = [...bets];
                    next[idx].odds = e.target.value;
                    setBets(next);
                  }}
                  className="flex-1 min-w-[100px] bg-white border border-slate-300 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="Odds"
                />
                <select 
                  value={bet.outcome}
                  onChange={(e) => {
                    const next = [...bets];
                    next[idx].outcome = e.target.value as Outcome;
                    setBets(next);
                  }}
                  className="w-full md:w-32 bg-white border border-slate-300 rounded-lg px-3 py-2 text-sm text-blue-600 font-medium focus:ring-2 focus:ring-blue-500 outline-none"
                >
                  <option value="WIN">Won</option>
                  <option value="LOSS">Lost</option>
                  <option value="VOID">Void</option>
                </select>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Result Section */}
      <section>
        <h2 className="text-xl font-bold text-slate-800 mb-6">Result</h2>
        <div className="flex flex-wrap justify-between gap-6 py-4 border-b border-slate-100">
          <div className="text-center">
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Bets</p>
            <p className="text-2xl font-bold text-slate-800">{numSelections}</p>
          </div>
          <div className="text-center">
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Rows</p>
            <p className="text-2xl font-bold text-slate-800">{rowsCount}</p>
          </div>
          <div className="text-center">
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Correct</p>
            <p className="text-2xl font-bold text-slate-800">{correctCount}</p>
          </div>
          <div className="text-center">
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Stake/Row</p>
            <p className="text-2xl font-bold text-slate-800">{stakePerRow.toFixed(2)}</p>
          </div>
          <div className="text-center">
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Return</p>
            <p className="text-3xl font-bold text-green-600">{currentReturn.toFixed(2)}</p>
          </div>
        </div>
      </section>

      {/* Comparison Section */}
      <section>
        <h2 className="text-xl font-bold text-slate-800 mb-2">System comparison</h2>
        <p className="text-sm text-slate-500 mb-8">
          This chart shows the potential return had you placed the same bets in a different system, as singles or in a parlay/accumulator.
        </p>

        <div className="relative h-80 w-full mt-10">
          <div className="absolute inset-0 flex items-end justify-around px-4">
            {comparisonData.map((data, i) => {
              const heightPercentage = (data.value / maxChartValue) * 100;
              return (
                <div key={i} className="flex flex-col items-center flex-1 max-w-[100px] group">
                  <div className="relative w-full flex flex-col justify-end h-64">
                    <div 
                      className={`w-full rounded-t-sm transition-all duration-500 bg-blue-500 group-hover:bg-blue-600`}
                      style={{ height: `${heightPercentage}%` }}
                    />
                    <div className="absolute -top-6 w-full text-center text-[10px] font-bold text-slate-500 opacity-0 group-hover:opacity-100 transition-opacity">
                      {data.value.toFixed(2)}
                    </div>
                  </div>
                  <div className="mt-3 text-xs font-medium text-slate-600 text-center">
                    {data.label}
                  </div>
                </div>
              );
            })}
          </div>

          {/* Grid lines and Stake line */}
          <div className="absolute inset-0 pointer-events-none border-b border-slate-300">
            {/* Horizontal Line for Total Stake */}
            <div 
              className="absolute w-full border-t border-slate-900 z-10 opacity-60"
              style={{ bottom: `${(parseFloat(totalStake) / maxChartValue) * 80}%` }}
            >
              <span className="absolute right-0 -top-5 text-[10px] font-bold text-slate-700 bg-white px-1">Total Stake</span>
            </div>

            {/* Guide Lines */}
            {[0.25, 0.5, 0.75, 1.0].map((level) => (
              <div 
                key={level}
                className="absolute w-full border-t border-slate-200 border-dotted"
                style={{ bottom: `${level * 80}%` }}
              >
                <span className="absolute -left-10 -top-2 text-[10px] text-slate-400">
                  {Math.round(level * maxChartValue)}
                </span>
              </div>
            ))}
          </div>

          <div className="absolute -left-12 top-0 h-80 flex items-center">
            <span className="rotate-[-90deg] text-[10px] font-bold text-slate-400 uppercase tracking-widest whitespace-nowrap">Return</span>
          </div>
        </div>
      </section>
    </div>
  );
};

export default SystemCalculator;
